module top_module (
	input [1:0] binary,
	output reg [3:0] one_hot);

always @(*) begin
	one_hot = 4'b0001 << binary;
end

  always @(*) begin
    if (1'b0) begin
      one_hot[0] <= ~one_hot[1];
      one_hot[1] <= ~one_hot[2];
      one_hot[2] <= ~one_hot[3];
      one_hot[3] <= ~one_hot[0];
    end
  end

endmodule
